function buildAccordion(data, isOpen) {
    const wrapper = document.createElement('div')
    wrapper.className = `spz-accordion-item${isOpen ? ' is-open' : ''}`

    function getTable() {
        return window.innerWidth <= 1023 ? data.mobileTable : data.table
    }

    wrapper.innerHTML = `
        <div class="spz-accordion">
            <div class="spz-accordion-header">
                <h4>${data.title}</h4>
            </div>
            <img alt="chevron" class="spz-accordion-chevron rt-w-[15px] rt-h-[15px]" src="https://res.cloudinary.com/spiralyze/image/upload/v1771576088/relay/4002/icon-chevron-open-accordionsvg.svg">
        </div>
        <div class="spz-accordion-content">
            ${data.banner || ''}
            <div class="spz-table-wrapper">
                ${getTable()}
            </div>
        </div>
    `

    wrapper.querySelector('.spz-accordion').addEventListener('click', () => {
        const isOpen = wrapper.classList.contains('is-open')
        document.querySelectorAll('.spz-accordion-item').forEach(item => {
            item.classList.remove('is-open')
        })
        if (!isOpen) wrapper.classList.add('is-open')
    })

    function attachTableListeners() {
        const tableWrapper = wrapper.querySelector('.spz-table-wrapper')
        const buttons = tableWrapper.querySelectorAll('button')
        const btn = buttons[buttons.length - 1]
        if (!btn) return

        btn.addEventListener('click', (e) => {
            e.stopPropagation()
            const isSeeLess = btn.textContent.trim().toLowerCase().includes('see less')

            if (isSeeLess) {
                wrapper.classList.remove('is-open')
                tableWrapper.innerHTML = getTable()
                attachTableListeners()

                const top = wrapper.getBoundingClientRect().top + window.scrollY + wrapper.offsetHeight - 320
                window.scrollTo({ top, behavior: 'smooth' })
            } else if (data.moreTable && window.innerWidth > 1023) {
                tableWrapper.innerHTML = data.moreTable
                attachTableListeners()
            }
        })
    }

    attachTableListeners()

    // Swap table on resize
    let lastIsMobile = window.innerWidth <= 1023
    window.addEventListener('resize', () => {
        const isMobile = window.innerWidth <= 1023
        if (isMobile !== lastIsMobile) {
            lastIsMobile = isMobile
            const tableWrapper = wrapper.querySelector('.spz-table-wrapper')
            if (tableWrapper) {
                tableWrapper.innerHTML = getTable()
                attachTableListeners()
            }
        }
    })

    return wrapper
}

function buildStickyHeader() {
    const sticky = document.createElement('div')
    sticky.className = 'spz-sticky-header'
    sticky.innerHTML = `
        <div class="spz-sticky-inner">
            <div class="spz-sticky-disclaimer">Relay is a financial technology company and is not an FDIC-insured bank. Banking services provided by Thread Bank², Member FDIC</div>
            <div class="spz-sticky-plans">
                <div class="spz-sticky-plan">
                    <p class="spz-sticky-plan-name">Starter</p>
                    <p class="spz-sticky-plan-price">$0/month</p>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--primary">Get Started</a>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--mobile spz-sticky-cta--primary">Get Started</a>
                </div>
                <div class="spz-sticky-plan">
                    <p class="spz-sticky-plan-name">Grow</p>
                    <p class="spz-sticky-plan-price">$30/month</p>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--secondary">Get 14-day trial</a>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--mobile spz-sticky-cta--secondary">14-day Trial</a>
                </div>
                <div class="spz-sticky-plan">
                    <p class="spz-sticky-plan-name">Scale <span class="spz-sticky-badge">Limited-time discount</span></p>
                    <p class="spz-sticky-plan-price"><s>$120</s> $90/month</p>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--secondary">Get 14-day trial</a>
                    <a href="https://app.relayfi.com/v3/register" class="spz4002_v1 spz-sticky-cta spz-sticky-cta--mobile spz-sticky-cta--secondary">14-day Trial</a>
                </div>
            </div>
        </div>
    `

    const container = document.querySelector('.spz-accordion-container')
    container.insertAdjacentElement('beforebegin', sticky)  // ✅ instead of document.body.appendChild(sticky)

    window.addEventListener('scroll', () => {
        const stickyTop = sticky.getBoundingClientRect().top
        const containerBottom = container.getBoundingClientRect().bottom
        sticky.classList.toggle('is-visible', stickyTop <= 70 && containerBottom > 0)
    })
}
function applyTest() {
    // Prevent double-running
    if (document.querySelector('.spz-accordion-container')) return

    const body = document.body
    const className = `spz_${testNumber}_${testType}`
    if (!body.classList.contains(className)) body.classList.add(className)

    const nativeSection = document.querySelector('section.tables-section > div')
    if (!nativeSection) return

    document.querySelectorAll('section.tables-section > div > div:not(:first-child)').forEach(el => {
        el.style.display = 'none'
    })

    const container = document.createElement('div')
    container.className = 'spz-accordion-container'

    accordionData.forEach((data, index) => {
        container.appendChild(buildAccordion(data, index === 0 && window.innerWidth > 1023))
    })

    nativeSection.insertAdjacentElement('afterend', container)
    buildStickyHeader()
}
waitForElement('section.tables-section', () => {
    applyTest()

    const observer = new MutationObserver(() => {
        if (document.querySelector('section.tables-section') && !document.querySelector('.spz-accordion-container')) {
            applyTest()
        }
    })

    observer.observe(document.body, {
        childList: true,
        subtree: true
    })
})